-- ================================================================
-- Table api_tokens (nouvelle — API Interopérabilité V1)
-- ================================================================
CREATE TABLE IF NOT EXISTS \`api_tokens\` (
  \`id\` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  \`nom\` varchar(255) NOT NULL,
  \`organisation_cliente\` varchar(255) DEFAULT NULL,
  \`token\` varchar(64) NOT NULL,
  \`prefix\` varchar(8) NOT NULL,
  \`permissions\` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT '[]',
  \`rate_limit\` int(11) NOT NULL DEFAULT 60,
  \`expires_at\` timestamp NULL DEFAULT NULL,
  \`last_used_at\` timestamp NULL DEFAULT NULL,
  \`last_used_ip\` varchar(45) DEFAULT NULL,
  \`total_requests\` int(11) NOT NULL DEFAULT 0,
  \`est_actif\` tinyint(1) NOT NULL DEFAULT 1,
  \`notes\` text DEFAULT NULL,
  \`created_at\` timestamp NULL DEFAULT NULL,
  \`updated_at\` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (\`id\`),
  UNIQUE KEY \`api_tokens_token_unique\` (\`token\`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

