INSERT INTO \`organisation_types\` (\`id\`, \`code\`, \`nom\`, \`description\`, \`couleur\`, \`icone\`, \`is_lucratif\`, \`nb_min_fondateurs_majeurs\`, \`nb_min_adherents_creation\`, \`guide_creation\`, \`texte_legislatif\`, \`loi_reference\`, \`is_active\`, \`ordre\`, \`metadata\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'association', 'Association 1', 'Organisation à but non lucratif regroupant des personnes autour d\'objectifs communs dans les domaines social, culturel, éducatif, sportif ou professionnel.', '#007bff', 'fa-users', '0', '1', '2', '## Étapes de création d\'une association\r\n\r\n1. **Rédiger les statuts** : Document définissant les règles de fonctionnement\r\n2. **Constituer le bureau** : Nommer président, secrétaire général, trésorier\r\n3. **Tenir l\'assemblée générale constitutive** : Réunion des membres fondateurs\r\n4. **Préparer le dossier** : Rassembler tous les documents requis\r\n5. **Déposer la demande** : Soumettre le dossier complet au SGLP\r\n\r\n## Documents à fournir\r\n- Statuts signés par tous les fondateurs\r\n- PV de l\'assemblée générale constitutive\r\n- Liste des membres fondateurs et adhérents\r\n- Pièces d\'identité des dirigeants\r\n- Casier judiciaire des dirigeants', 'Conformément à la Constitution de la République Gabonaise et aux lois en vigueur, toute personne a le droit de créer une association à but non lucratif. Les associations doivent se déclarer auprès des autorités compétentes et respecter les principes de transparence et de légalité dans leurs activités.', 'Loi 35/62 du 10 décembre 1962', '1', '1', '{\"popularite\": \"tres_elevee\", \"taux_approbation\": 85, \"delai_traitement_moyen_jours\": 30}', '2025-10-16 19:23:35', '2025-10-18 16:55:55', NULL);
INSERT INTO \`organisation_types\` (\`id\`, \`code\`, \`nom\`, \`description\`, \`couleur\`, \`icone\`, \`is_lucratif\`, \`nb_min_fondateurs_majeurs\`, \`nb_min_adherents_creation\`, \`guide_creation\`, \`texte_legislatif\`, \`loi_reference\`, \`is_active\`, \`ordre\`, \`metadata\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'ong', 'ONG (Organisation Non Gouvernementale)', 'Organisation à but non lucratif, indépendante de tout gouvernement, œuvrant dans des domaines humanitaires, de développement, de défense des droits ou d\'environnement.', '#28a745', 'fa-hands-helping', '0', '3', '15', '## Création d\'une ONG au Gabon\n\n### Conditions spécifiques\n- Objectif humanitaire, social ou de développement clairement défini\n- Indépendance vis-à-vis des gouvernements\n- Transparence financière obligatoire\n- Capacité à justifier des sources de financement\n\n### Procédure\n1. Élaboration du projet associatif\n2. Rédaction des statuts conformes aux normes internationales\n3. Constitution d\'un conseil d\'administration\n4. Assemblée générale constitutive\n5. Dépôt du dossier complet\n6. Obtention de l\'agrément ONG\n\n### Engagements\n- Rapport d\'activités annuel obligatoire\n- Audit financier régulier\n- Respect des conventions internationales', 'Les ONG sont régies par les dispositions spécifiques relatives aux associations à but non lucratif, avec des exigences supplémentaires en matière de transparence, de gouvernance et de reporting. Elles doivent démontrer leur indépendance et leur engagement dans des causes d\'intérêt général.', 'Loi 35/62 + Décret d\'application ONG', '1', '2', '{\"popularite\": \"elevee\", \"taux_approbation\": 75, \"exigences_supplementaires\": true, \"delai_traitement_moyen_jours\": 45}', '2025-10-16 19:23:35', '2025-10-16 19:23:35', NULL);
INSERT INTO \`organisation_types\` (\`id\`, \`code\`, \`nom\`, \`description\`, \`couleur\`, \`icone\`, \`is_lucratif\`, \`nb_min_fondateurs_majeurs\`, \`nb_min_adherents_creation\`, \`guide_creation\`, \`texte_legislatif\`, \`loi_reference\`, \`is_active\`, \`ordre\`, \`metadata\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'parti_politique', 'Parti politique', 'Organisation politique permanente qui participe à l\'expression du suffrage, concourt à l\'animation de la vie politique et à la formation de l\'opinion publique.', '#dc3545', 'fa-landmark', '0', '1', '3', '## Création d\'un parti politique\r\n\r\n### Conditions strictes\r\n- Respect des principes démocratiques\r\n- Caractère national (présence dans plusieurs provinces)\r\n- Programme politique clairement défini\r\n- Engagement à respecter la Constitution\r\n\r\n### Membres fondateurs\r\n- Minimum 50 fondateurs majeurs\r\n- Nationalité gabonaise obligatoire\r\n- Jouissance des droits civiques\r\n- Absence de condamnations incompatibles\r\n\r\n### Procédure\r\n1. Rédaction des statuts et du programme politique\r\n2. Constitution des organes dirigeants nationaux\r\n3. Établissement de la représentation territoriale\r\n4. Assemblée générale constitutive\r\n5. Dépôt de la déclaration\r\n6. Publication au Journal Officiel\r\n\r\n### Obligations\r\n- Tenue de congrès réguliers\r\n- Transparence financière renforcée\r\n- Déclaration des sources de financement\r\n- Respect du pluralisme politique', 'Les partis politiques concourent à l\'expression du suffrage. Ils se forment et exercent leur activité librement dans le respect des principes de la souveraineté nationale, de la démocratie, de l\'intégrité territoriale et de l\'ordre public. Ils doivent respecter les principes énoncés dans la Constitution.', 'Loi 5/2015 sur les partis politiques', '1', '3', '{\"popularite\": \"moyenne\", \"taux_approbation\": 60, \"verification_renforcee\": true, \"exigences_territoriales\": true, \"delai_traitement_moyen_jours\": 60}', '2025-10-16 19:23:35', '2026-02-11 19:21:21', NULL);
INSERT INTO \`organisation_types\` (\`id\`, \`code\`, \`nom\`, \`description\`, \`couleur\`, \`icone\`, \`is_lucratif\`, \`nb_min_fondateurs_majeurs\`, \`nb_min_adherents_creation\`, \`guide_creation\`, \`texte_legislatif\`, \`loi_reference\`, \`is_active\`, \`ordre\`, \`metadata\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('4', 'confession_religieuse', 'Confession religieuse', 'Organisation religieuse ou cultuelle réunissant des fidèles autour d\'une foi commune, dans le respect de la liberté de conscience et de culte.', '#6f42c1', 'fa-church', '0', '5', '20', '## Déclaration d\'une confession religieuse\n\n### Principes fondamentaux\n- Liberté de culte garantie par la Constitution\n- Respect de l\'ordre public et de la laïcité de l\'État\n- Tolérance et respect des autres confessions\n- Transparence dans l\'organisation et les activités\n\n### Catégories reconnues\n- Églises chrétiennes\n- Communautés islamiques\n- Autres confessions monothéistes\n- Mouvements spirituels reconnus\n\n### Procédure de déclaration\n1. Définition des principes doctrinaux\n2. Rédaction des statuts religieux\n3. Constitution du clergé ou des responsables religieux\n4. Désignation du représentant légal\n5. Assemblée constitutive des fidèles\n6. Dépôt de la déclaration\n\n### Documents spécifiques\n- Profession de foi ou doctrine religieuse\n- Références théologiques\n- Organisation hiérarchique (si applicable)\n- Règlement intérieur du culte\n\n### Engagements\n- Respect de la dignité humaine\n- Non-discrimination\n- Transparence financière\n- Rapport d\'activités annuel', 'La liberté de conscience et de culte est garantie par la Constitution. L\'État respecte toutes les croyances. Les confessions religieuses sont libres de s\'organiser et de pratiquer leur culte dans le respect des lois de la République, de l\'ordre public et des bonnes mœurs.', 'Loi 15/2005 sur la liberté religieuse', '1', '4', '{\"popularite\": \"moyenne\", \"taux_approbation\": 70, \"verification_doctrinale\": true, \"delai_traitement_moyen_jours\": 35}', '2025-10-16 19:23:35', '2025-10-16 19:23:35', NULL);
INSERT INTO \`organisation_types\` (\`id\`, \`code\`, \`nom\`, \`description\`, \`couleur\`, \`icone\`, \`is_lucratif\`, \`nb_min_fondateurs_majeurs\`, \`nb_min_adherents_creation\`, \`guide_creation\`, \`texte_legislatif\`, \`loi_reference\`, \`is_active\`, \`ordre\`, \`metadata\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('5', 'syndicat', 'Syndicat', 'Un syndicat est une association de personnes destinée à la défense de leurs intérêts professionnels communs. Le mot \"syndicat\", se retrouve, notamment dans le droit de la copropriété immobilière, en droit bancaire et en droit du travail.', '#007bff', 'fa-users', '0', '1', '1', 'Un syndicat est une association de personnes destinée à la défense de leurs intérêts professionnels communs. Le mot \"syndicat\", se retrouve, notamment dans le droit de la copropriété immobilière, en droit bancaire et en droit du travail.', 'Les textes réglementaires principaux concernant les syndicats au Gabon sont la Constitution gabonaise et le Code du travail, qui garantissent le droit à la liberté syndicale et en définissent les modalités. Des lois spécifiques, comme la loi n° 18/92 pour les agents de l\'État, précisent les conditions de constitution et de fonctionnement des syndicats professionnels. Les conventions collectives, les statuts de syndicats et les décrets d\'application complètent le cadre juridique.', 'Loi 35/62 du 10 décembre 1962', '1', '5', NULL, '2025-10-18 17:12:41', '2025-10-18 17:16:37', NULL);
