>                                                                          \r\nDIRECTION DES PARTIS POLITIQUES,<br/>\r\nASSOCIATIONS ET LIBERTE DE CULTE     \r\n</div>\r\n        </td>\r\n    </tr>\r\n</table>', '<div style=\"margin-top: 10px; padding:0px;\">\r\n    <table width=\"100%\">\r\n        <tr>\r\n<td width=\"55%\"></td>\r\n            <td width=\"45%\" style=\"font-size: 13px;\">\r\n            <p><strong>Fait à Libreville, Le __________________</strong></p>\r\n<div style=\"text-align: center; font-size: 15px;\"> <br/>\r\n                Le Ministre de l’Intérieur, de la Sécurité<br/>\r\n                    et de la Décentralisation \r\n<br/><br/><br/><br/><br/>                                                               \r\n<p><strong>Adrien NGUEMA MBA</strong></p>\r\n</div>\r\n            </td>\r\n        </tr>\r\n    </table>\r\n</div>', '1', '1', '0', '2025-10-26 11:56:04', '2026-02-19 14:02:56');
INSERT INTO \`document_templates\` (\`id\`, \`organisation_type_id\`, \`operation_type_id\`, \`workflow_step_id\`, \`code\`, \`nom\`, \`description\`, \`template_path\`, \`layout_path\`, \`type_document\`, \`variables\`, \`required_variables\`, \`pdf_config\`, \`has_qr_code\`, \`has_watermark\`, \`has_signature\`, \`signature_image\`, \`header_text\`, \`signature_text\`, \`is_active\`, \`auto_generate\`, \`generation_delay_hours\`, \`created_at\`, \`updated_at\`) VALUES ('2', '1', '1', '1', 'ASSOC_CREATION_VALID_TECH', 'Accusé validation technique - Association', 'Accusé de réception après validation technique du dossier', 'documents.templates.association.creation.step-1-recepisse-depot', 'documents.layouts.official', 'accuse_reception', '{\"agent\": [\"nom\"], \"dossier\": [\"numero_dossier\"], \"document\": [\"numero_document\", \"date_generation\", \"qr_code_url\"], \"organisation\": [\"nom\", \"sigle\"]}', '[\"organisation.nom\", \"document.numero_document\"]', '{\"format\": \"a4\", \"margins\": {\"top\": 20, \"left\": 15, \"right\": 15, \"bottom\": 20}, \"orientation\": \"portrait\"}', '1', '0', '1', NULL, '<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-bottom: 10px;\">\r\n    <tr>\r\n        <td width=\"50%\" style=\"text-align: left; vertical-align: top;\">\r\n            <div style=\"font-weight: bold; color: #006633;\">RÉPUBLIQUE GABONAISE</div>\r\n            <div style=\"font-size: 10px;\">Union - Travail - Justice</div>\r\n        </td>\r\n        <td width=\"50%\" style=\"text-align: right; vertical-align: top;\">\r\n            <div style=\"font-weight: bold; font-size: 11px;\">\r\n                MINISTÈRE DE L\'INTÉRIEUR\r\n            </div>\r\n            <div style=\"font-size: 10px;\">\r\n                Direction Générale des Libertés Publiques<br>\r\n                BP 2110 - Libreville - Gabon\r\n            </div>\r\n        </td>\r\n    </tr>\r\n</table>', '<div style=\"margin-top: 30px; padding: 15px; border: 1px s