</li>\r\n      <li>SG</li>\r\n      <li>DGAT</li>\r\n      <li>MINISTERE CONCERNE</li>\r\n      <li>J.O</li>\r\n</ul>\r\n</td>\r\n            <td width=\"45%\" style=\"font-size: 12pt;\">\r\n            <p><strong>Fait à Libreville, Le __________________</strong></p>\r\n<div style=\"text-align: center; font-size: 14pt;\"> <br/>\r\n                Le Ministre de l’Intérieur, de la Sécurité<br/>\r\n                    et de la Décentralisation \r\n<br/><br/><br/><br/><br/>                                                               \r\n<p><strong>Hermann IMMONGAULT</strong></p>\r\n</div>\r\n            </td>\r\n        </tr>\r\n</table>\r\n</div>', '1', '0', '0', '2025-12-28 22:05:52', '2025-12-28 22:40:31');
