INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('1', 'Nouvelle procédure de formalisation simplifiée', 'nouvelle-procedure-formalisation-simplifiee', 'Le Ministère de l\'Intérieur annonce la simplification des démarches administratives pour la création d\'associations.', '<p>Le Ministère de l\'Intérieur et de la Sécurité a le plaisir d\'annoncer la mise en place d\'une nouvelle procédure simplifiée pour la formalisation des organisations associatives.</p><h3>Les principales améliorations</h3><ul><li>Réduction du nombre de documents requis de 12 à 7</li><li>Délai de traitement ramené de 30 à 15 jours ouvrables</li><li>Possibilité de soumettre tous les documents en ligne</li></ul>', NULL, 'Réglementation', 'Administration PNGDI', 'publie', '234', '1', '2025-01-15 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('2', 'Séminaire national sur les associations', 'seminaire-national-associations-2025', 'Un séminaire de formation pour les responsables d\'associations se tiendra du 25 au 27 janvier 2025 à Libreville.', '<p>Le Ministère de l\'Intérieur organise un séminaire national de formation pour les responsables d\'associations du 25 au 27 janvier 2025 à Libreville.</p><h3>Programme</h3><ul><li>Jour 1 : Cadre juridique et réglementaire</li><li>Jour 2 : Gestion administrative et financière</li><li>Jour 3 : Communication et développement</li></ul>', NULL, 'Événement', 'Direction des Associations', 'publie', '156', '0', '2025-01-10 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('3', 'Mise à jour des documents requis pour les ONG', 'mise-a-jour-documents-requis-ong', 'La liste des documents nécessaires pour la création d\'ONG a été actualisée.', '<p>Suite aux recommandations du comité de simplification administrative, la liste des documents requis pour la création d\'ONG a été révisée.</p>', NULL, 'Documentation', 'Service Juridique', 'publie', '412', '0', '2025-01-05 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('4', 'Bilan 2024 : 200 nouvelles organisations créées', 'bilan-annuel-2024-organisations', 'Le PNGDI dresse un bilan positif de l\'année 2024 avec plus de 200 nouvelles organisations formalisées.', '<p>Le PNGDI présente son bilan annuel pour 2024, marquée par une croissance de 35% du nombre d\'organisations.</p>', NULL, 'Statistiques', 'Administration PNGDI', 'publie', '523', '0', '2025-01-02 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('5', 'Lancement officiel de la nouvelle plateforme PNGDI', 'nouvelle-plateforme-pngdi-lancee', 'La nouvelle version du portail PNGDI est maintenant disponible avec une interface modernisée.', '<p>Nous sommes heureux d\'annoncer le lancement officiel de la nouvelle version du PNGDI.</p>', NULL, 'Annonce', 'Équipe Technique', 'publie', '789', '1', '2024-12-20 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_actualites\` (\`id\`, \`titre\`, \`slug\`, \`extrait\`, \`contenu\`, \`image\`, \`categorie\`, \`auteur\`, \`statut\`, \`vues\`, \`en_une\`, \`date_publication\`, \`created_at\`, \`updated_at\`) VALUES ('6', 'Guide pratique : Déclaration annuelle 2025', 'guide-declaration-annuelle-2025', 'Tout ce que vous devez savoir pour préparer et soumettre votre déclaration annuelle 2025.', '<p>La période de déclaration annuelle 2025 approche. Voici tout ce que vous devez savoir pour être en conformité.</p>', NULL, 'Guide', 'Service Conformité', 'publie', '345', '0', '2024-12-15 00:00:00', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
