INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('1', 'Qu\'est-ce que le PNGDI ?', 'Le Portail National de Gestion des Libertés Individuelles (PNGDI) est une plateforme numérique mise en place par le Ministère de l\'Intérieur pour faciliter la formalisation et la gestion des organisations associatives, religieuses et politiques au Gabon.', 'Général', '1', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('2', 'Qui peut utiliser le PNGDI ?', 'Le portail est accessible à toute personne souhaitant créer ou gérer une association, une ONG, un parti politique ou une confession religieuse au Gabon.', 'Général', '2', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('3', 'Le service est-il gratuit ?', 'L\'inscription et l\'utilisation du portail sont gratuites. Cependant, certaines procédures administratives peuvent être soumises à des frais réglementaires selon la législation en vigueur.', 'Général', '3', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('4', 'Quels sont les documents nécessaires pour créer une association ?', 'Pour créer une association, vous devez fournir : les statuts, le procès-verbal de l\'assemblée constitutive, la liste des membres fondateurs, les copies de pièces d\'identité des dirigeants, et un justificatif de domicile du siège social.', 'Création', '1', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('5', 'Combien de temps prend le traitement d\'un dossier ?', 'Le délai de traitement varie selon le type d\'organisation : 15 jours ouvrables pour une association, 30 jours pour une ONG, 45 jours pour un parti politique, et 30 jours pour une confession religieuse.', 'Création', '2', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('6', 'Puis-je créer plusieurs organisations ?', 'Un utilisateur peut créer plusieurs associations ou ONG. Cependant, il ne peut créer qu\'un seul parti politique actif à la fois, conformément à la réglementation.', 'Création', '3', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('7', 'Puis-je suivre l\'avancement de mon dossier en ligne ?', 'Oui, une fois votre dossier soumis, vous pouvez suivre son avancement en temps réel depuis votre espace personnel.', 'Technique', '1', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('8', 'Comment récupérer mon mot de passe ?', 'Cliquez sur \"Mot de passe oublié\" sur la page de connexion. Entrez votre adresse email, et vous recevrez un lien de réinitialisation valable 24 heures.', 'Technique', '2', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('9', 'Quels formats de documents sont acceptés ?', 'Le portail accepte les formats PDF, JPEG, PNG pour les documents scannés. La taille maximale par fichier est de 5 MB.', 'Technique', '3', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('10', 'Quand dois-je faire ma déclaration annuelle ?', 'La déclaration annuelle doit être soumise avant le 31 mars de chaque année. Elle comprend le rapport d\'activités, le bilan financier et la liste actualisée des membres du bureau.', 'Gestion', '1', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('11', 'Que se passe-t-il si je ne fais pas ma déclaration annuelle ?', 'Le non-respect de l\'obligation de déclaration annuelle peut entraîner des sanctions allant de l\'avertissement à la suspension temporaire ou définitive de l\'agrément.', 'Gestion', '2', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
INSERT INTO \`portail_faqs\` (\`id\`, \`question\`, \`reponse\`, \`categorie\`, \`ordre\`, \`est_actif\`, \`created_at\`, \`updated_at\`) VALUES ('12', 'Comment modifier les informations de mon organisation ?', 'Connectez-vous à votre espace personnel et accédez à la section \"Gérer mon organisation\". Vous pourrez y modifier les informations et soumettre les documents justificatifs nécessaires.', 'Gestion', '3', '1', '2026-03-09 21:32:04', '2026-03-09 21:32:04');
